module top_module(
  input [7:0] obf_I,
  input [2:0] S,
  output reg Y
);always @*
  begin
    case (S)
      3'b000: Y = obf_I[0];
      3'b001: Y = obf_I[1];
      3'b010: Y = obf_I[2];
      3'b011: Y = obf_I[3];
      3'b100: Y = obf_I[4];
      3'b101: Y = obf_I[5];
      3'b110: Y = obf_I[6];
      3'b111: Y = obf_I[7];
    endcase
  end

endmodule
